class IsPhoneNumber(DirtyEquals[str]):
    """
    A class that checks if a value is a valid phone number, optionally restricted to a specific country's format.
    """

    _generic_pattern = re.compile(r'\+?\d{7,15}')
    _fallback_international_pattern = re.compile(r'\+\d{7,15}')
    _cleanup_pattern = re.compile(r'[\s.\-()]')
    _country_patterns: Dict[str, Dict[str, 're.Pattern[str]']] = {
        'US': {
            'international': re.compile(r'\+1\d{10}'),
            'national': re.compile(r'\d{10}'),
        },
        'GB': {
            'international': re.compile(r'\+44\d{9,10}'),
            'national': re.compile(r'0\d{9,10}'),
        },
    }

    def __init__(self, country: Optional[str] = None):
        """
        Args:
            country: ISO 3166-1 alpha-2 country code used to validate the number against that country's format.
                If omitted, generic international/national phone number formats are accepted.

        Note that for countries without specific rules built in, `IsPhoneNumber` falls back to a generic
        international format check (`+` followed by 7 to 15 digits).

        ```py title="IsPhoneNumber"
        from dirty_equals import IsPhoneNumber

        assert '+1-555-123-4567' == IsPhoneNumber
        assert '555-123-4567' == IsPhoneNumber
        assert 'not-a-number' != IsPhoneNumber
        assert 1235551234 != IsPhoneNumber

        assert '555-123-4567' == IsPhoneNumber('US')
        assert '+1-555-123-4567' == IsPhoneNumber('US')
        assert '020 7946 0958' == IsPhoneNumber('GB')
        assert '+44 20 7946 0958' == IsPhoneNumber('GB')
        assert '555-123-4567' != IsPhoneNumber('GB')
        assert '020 7946 0958' != IsPhoneNumber('US')
        assert '15551234567' != IsPhoneNumber('US')

        assert '+33 1 42 68 53 00' == IsPhoneNumber('FR')
        ```
        """
        self.country = country
        super().__init__(country if country else plain_repr('*'))

    def equals(self, other: Any) -> bool:
        if not isinstance(other, str):
            return False

        cleaned = self._cleanup_pattern.sub('', other)
        if not cleaned:
            return False

        if self.country is None:
            return bool(self._generic_pattern.fullmatch(cleaned))

        patterns = self._country_patterns.get(self.country.upper())
        if patterns is None:
            return bool(self._fallback_international_pattern.fullmatch(cleaned))

        return bool(patterns['international'].fullmatch(cleaned) or patterns['national'].fullmatch(cleaned))

